func firstLetterR(s string) string {
	if s == "" {
		return "?"
	}
	r := []rune(s)
	return strings.ToUpper(string(r[0]))
}

func fmtMarkVal(v *float64) string {
	if v == nil {
		return "0.000"
	}
	return fmt.Sprintf("%.3f", *v)
}

func fmtPtrVal(v *float64) string {
	if v == nil {
		return "0.000"
	}
	return fmt.Sprintf("%.3f", *v)
}

